"use client";

import { type MenuProps, Menu as MenuRoot } from "./menu";
import { MenuDivider, type MenuDividerProps } from "./menu-divider";
import { MenuGroup, type MenuGroupProps } from "./menu-group";
import { MenuItem, type MenuItemProps } from "./menu-item";
import { MenuItemCheckbox, type MenuItemCheckboxProps } from "./menu-item-checkbox";
import { MenuItemRadio, type MenuItemRadioProps } from "./menu-item-radio";
import { MenuLabel, type MenuLabelProps } from "./menu-label";
import {
  MenuSub,
  MenuSubContent,
  type MenuSubContentProps,
  type MenuSubProps,
  MenuSubTrigger,
  type MenuSubTriggerProps,
} from "./menu-sub";

const Menu = Object.assign(MenuRoot, {
  Item: MenuItem,
  ItemCheckbox: MenuItemCheckbox,
  ItemRadio: MenuItemRadio,
  Divider: MenuDivider,
  Group: MenuGroup,
  Label: MenuLabel,
  Sub: MenuSub,
  SubTrigger: MenuSubTrigger,
  SubContent: MenuSubContent,
});

export { Menu, type MenuProps };
export { MenuItem, type MenuItemProps };
export { MenuItemCheckbox, type MenuItemCheckboxProps };
export { MenuItemRadio, type MenuItemRadioProps };
export { MenuDivider, type MenuDividerProps };
export { MenuGroup, type MenuGroupProps };
export { MenuLabel, type MenuLabelProps };
export { MenuSub, type MenuSubProps };
export { MenuSubTrigger, type MenuSubTriggerProps };
export { MenuSubContent, type MenuSubContentProps };

"use client";

import {
  type ComponentPropsWithRef,
  type KeyboardEvent,
  type ReactNode,
  useCallback,
  useId,
  useMemo,
  useRef,
  useState,
} from "react";
import { useComposedRefs } from "@/hooks/use-composed-refs";
import {
  collectListboxItems,
  getEncodedListboxItemId,
  type ListboxMetadataItem,
  useListbox,
} from "@/hooks/use-listbox";
import { useSelectableCollection } from "@/lib/selectable-collection";
import { cn } from "@/lib/utils";
import { type CustomActivator, MenuContext, type MenuContextValue } from "./menu-context";
import { MenuGroup } from "./menu-group";
import { MenuItem } from "./menu-item";
import { MenuItemCheckbox } from "./menu-item-checkbox";
import { MenuItemRadio } from "./menu-item-radio";

/**
 * @typeParam TId - Convenience assertion for the id union surfaced through
 * `selectedId`/`onSelect`/`onHighlightChange`. Ids originate from `Menu.Item`
 * children props and are asserted to `TId`, not validated; activating an
 * unregistered id warns in development (see the dev guard in `wrappedActivate`).
 */
export interface MenuProps<TId extends string = string>
  extends Omit<ComponentPropsWithRef<"div">, "aria-label" | "children" | "onKeyDown" | "onSelect"> {
  /**
   * Controlled selected item id. Pair with onSelect. Switches item role to "menuitemradio" with
   * aria-checked.
   */
  selectedId?: TId | null;
  /**
   * Initial selected id for uncontrolled mode. Setting this to a non-null value enables
   * selection semantics.
   */
  defaultSelectedId?: TId | null;
  /** Controlled highlighted (focused) item id. Pair with onHighlightChange. */
  highlighted?: TId | null;
  /** Initial highlighted id for uncontrolled mode. */
  defaultHighlighted?: TId | null;
  /** Fired when an item is activated by click, Enter, or Space. */
  onSelect?: (id: TId) => void;
  /** Fired when the highlighted item changes via arrow keys, typeahead, or mouse. */
  onHighlightChange?: (value: TId | null) => void;
  /** Fired when Escape or Tab is pressed. */
  onClose?: () => void;
  /**
   * Visual layout. `detail` renders taller, divider-separated rows with a right-aligned value
   * column, for menus where each item carries a status or summary value.
   */
  variant?: "default" | "detail";
  /** When true, arrow navigation wraps from last item to first and vice versa. */
  wrap?: boolean;
  /** MenuItem and MenuDivider children. */
  children: ReactNode;
  /** Auto-focus the menu container on mount so arrow keys work without an explicit click. */
  autoFocus?: boolean;
  /** Accessible name for the menu container. */
  "aria-label"?: string;
  /** Called after the built-in menu key handling runs. */
  onKeyDown?: (event: KeyboardEvent) => void;
}

/**
 * Terminal-styled selection list with keyboard navigation, highlighting and optional hotkey
 * indicators.
 */
export function Menu<TId extends string = string>({
  selectedId: controlledSelectedId,
  defaultSelectedId = null,
  highlighted: controlledHighlighted,
  defaultHighlighted = null,
  onSelect,
  onHighlightChange,
  onClose,
  variant = "default",
  wrap = true,
  className,
  "aria-label": ariaLabel,
  autoFocus,
  children,
  onKeyDown,
  ref,
  ...rootProps
}: MenuProps<TId>) {
  const idPrefix = useId();
  const menuRef = useRef<HTMLDivElement>(null);
  const composedRef = useComposedRefs(menuRef, ref);
  const customActivators = useRef<Map<string, CustomActivator>>(new Map());
  const [registrationsStarted, setRegistrationsStarted] = useState(false);
  const selectionEnabled = controlledSelectedId !== undefined || defaultSelectedId !== null;
  const itemRole = selectionEnabled ? "menuitemradio" : "menuitem";

  const { items: registeredItems, registerItem, unregisterItem } = useSelectableCollection(menuRef);
  const registeredMetadata = useMemo<ListboxMetadataItem<TId>[]>(
    () => registeredItems.map((item) => ({ id: item.value as TId, disabled: item.disabled })),
    [registeredItems],
  );
  const renderSeed = useMemo(
    () =>
      collectListboxItems<TId>(children, {
        itemTypes: [MenuItem, MenuItemCheckbox, MenuItemRadio],
        containerTypes: [MenuGroup],
      }),
    [children],
  );
  const items = registrationsStarted ? registeredMetadata : renderSeed;

  const handleRegisterItem = useCallback(
    (registrationId: string, value: string, disabled: boolean, element: HTMLElement | null) => {
      setRegistrationsStarted(true);
      registerItem(registrationId, value, disabled, element);
    },
    [registerItem],
  );

  const registerActivator = useCallback((id: string, handler: CustomActivator) => {
    customActivators.current.set(id, handler);
  }, []);

  const unregisterActivator = useCallback((id: string) => {
    customActivators.current.delete(id);
  }, []);

  const { selectedId, highlighted, handleItemActivate, handleItemHighlight, getContainerProps } =
    useListbox<TId>({
      selectedId: selectionEnabled ? controlledSelectedId : null,
      defaultSelectedId: selectionEnabled ? defaultSelectedId : null,
      highlighted: controlledHighlighted,
      defaultHighlighted,
      onSelect,
      onHighlightChange,
      wrap,
      idPrefix,
      onKeyDown: (e: KeyboardEvent) => {
        if ((e.key === "Enter" || e.key === " ") && highlighted !== null) {
          const handler = customActivators.current.get(highlighted);
          if (handler) {
            e.preventDefault();
            handler();
            return;
          }
        }
        if (e.key === "ArrowRight") {
          const container = menuRef.current;
          const activeId = container?.getAttribute("aria-activedescendant");
          if (activeId) {
            const activeEl = container?.ownerDocument.getElementById(activeId);
            if (activeEl?.getAttribute("aria-haspopup") === "menu") {
              e.preventDefault();
              activeEl.click();
              onKeyDown?.(e);
              return;
            }
          }
        }
        if (e.key === "Escape" && onClose) {
          // Consume the Escape so a menu inside a native <dialog> closes only the
          // menu instead of also firing the dialog's cancel event.
          e.preventDefault();
          onClose();
        }
        if (e.key === "Tab") onClose?.();
        onKeyDown?.(e);
      },
      role: "menu",
      itemRole,
      typeahead: true,
      autoFocus,
      items,
      getItemId: getEncodedListboxItemId,
      ref: composedRef,
    });

  const wrappedActivate = useCallback(
    (id: string) => {
      const handler = customActivators.current.get(id);
      if (handler) {
        handleItemHighlight(id as TId);
        handler();
        return;
      }
      if (process.env.NODE_ENV !== "production" && !items.some((item) => item.id === id)) {
        console.warn(
          `Menu: activated item id "${id}" is not registered. Render it through <Menu.Item> so it is collected.`,
        );
      }
      handleItemActivate(id as TId);
    },
    [handleItemActivate, handleItemHighlight, items],
  );

  const notifySelect = useCallback(
    (id: string) => {
      onSelect?.(id as TId);
    },
    [onSelect],
  );

  // Public TId narrows the API; internal context stays string-keyed because the
  // DOM uses data-value strings and child MenuItem ids are opaque to TS.
  const contextValue: MenuContextValue = useMemo(
    () => ({
      selectedId,
      highlighted,
      activate: wrappedActivate,
      notifySelect,
      highlight: handleItemHighlight as (id: string) => void,
      variant,
      idPrefix,
      itemRole,
      registerItem: handleRegisterItem,
      unregisterItem,
      registerActivator,
      unregisterActivator,
    }),
    [
      selectedId,
      highlighted,
      wrappedActivate,
      notifySelect,
      handleItemHighlight,
      variant,
      idPrefix,
      itemRole,
      handleRegisterItem,
      unregisterItem,
      registerActivator,
      unregisterActivator,
    ],
  );

  return (
    <MenuContext value={contextValue}>
      {/* biome-ignore lint/a11y/useAriaPropsSupportedByRole: getContainerProps applies role="menu"/"listbox" dynamically, which Biome cannot resolve; aria-label is valid for those roles. */}
      <div
        {...rootProps}
        {...getContainerProps()}
        data-slot="menu"
        aria-label={ariaLabel}
        className={cn("w-full relative outline-none", className)}
      >
        {children}
      </div>
    </MenuContext>
  );
}

"use client";

import {
  type ComponentPropsWithRef,
  type ReactNode,
  type Ref,
  useId,
  useLayoutEffect,
  useRef,
} from "react";
import { useComposedRefs } from "@/hooks/use-composed-refs";
import { getEncodedListboxItemId } from "@/hooks/use-listbox";
import { cn } from "@/lib/utils";
import { useMenuContext } from "./menu-context";
import { DefaultItemLayout, DetailItemLayout } from "./menu-item-layouts";
import { getItemState, menuItemBase, menuItemValue } from "./menu-item-variants";
import { useMenuItemInteractions } from "./use-menu-item-interactions";

/** Props for menu item. */
export interface MenuItemProps<TId extends string = string>
  extends Omit<
    ComponentPropsWithRef<"div">,
    "id" | "children" | "role" | "aria-checked" | "aria-disabled" | "data-value" | "ref"
  > {
  /** Stable identifier matched against selectedId/highlighted and passed to onSelect. */
  id: TId;
  /** Disables activation while keeping the item in the navigation order with aria-disabled. */
  disabled?: boolean;
  /** Danger applies destructive coloring for destructive actions. */
  variant?: "default" | "danger";
  /** Decorative hotkey label rendered as [n]. Does not bind a key listener. */
  hotkey?: number | string;
  /**
   * Leading icon rendered in the indicator slot. Replaces the default ▐/> indicator when
   * provided.
   */
  icon?: ReactNode;
  /** Detail variant only. Right-aligned value (badge, count, or status text). */
  value?: ReactNode;
  /** Color treatment for the detail value. */
  valueVariant?: "default" | "success" | "success-badge" | "muted";
  /** Item label. */
  children: ReactNode;
  /** Ref forwarded to the underlying element. */
  ref?: Ref<HTMLDivElement>;
}

/** Selectable item with optional hotkey, value, variant. */
export function MenuItem<TId extends string = string>({
  id,
  disabled = false,
  variant = "default",
  hotkey,
  icon,
  value,
  valueVariant = "default",
  children,
  className,
  ref,
  onClick,
  onFocus,
  onMouseDown,
  ...rootProps
}: MenuItemProps<TId>) {
  const {
    selectedId,
    highlighted,
    activate,
    highlight,
    variant: menuVariant,
    idPrefix,
    itemRole,
    registerItem,
    unregisterItem,
  } = useMenuContext();
  const registrationId = useId();
  const rootRef = useRef<HTMLDivElement>(null);
  const composedRef = useComposedRefs(rootRef, ref);

  useLayoutEffect(() => {
    registerItem(registrationId, id, disabled, rootRef.current);
    return () => unregisterItem(registrationId);
  }, [registerItem, unregisterItem, registrationId, id, disabled]);

  const isSelected = !disabled && selectedId === id;
  const isFocused = highlighted === id;
  const isActive = !disabled && (isFocused || isSelected);
  const isDanger = variant === "danger";
  const isDetail = menuVariant === "detail";
  const state = getItemState({ disabled, isFocused, isSelected });
  const itemId = getEncodedListboxItemId(idPrefix, id);

  const { handleClick, handleFocus, handleMouseDown } = useMenuItemInteractions({
    id,
    disabled,
    activate,
    highlight,
    onClick,
    onFocus,
    onMouseDown,
  });

  return (
    // biome-ignore lint/a11y/noStaticElementInteractions: menuitem with centralized keyboard handling — the menu container owns arrow/Enter/Space via useNavigation; the item only mirrors focus/click.
    // biome-ignore lint/a11y/useAriaPropsSupportedByRole: role is the dynamic itemRole (menuitem/menuitemradio) that Biome cannot resolve; aria-checked is valid for menuitemradio.
    // biome-ignore lint/a11y/useKeyWithClickEvents: Enter/Space activation is handled centrally by the menu container, not per item.
    <div
      {...rootProps}
      ref={composedRef}
      id={itemId}
      role={itemRole}
      tabIndex={-1}
      data-slot="menu-item"
      data-diffgazer-navigation-item="true"
      data-value={id}
      data-highlighted={isFocused ? "" : undefined}
      aria-checked={itemRole === "menuitemradio" ? isSelected : undefined}
      aria-disabled={disabled || undefined}
      data-selected={isSelected ? "" : undefined}
      onMouseDown={handleMouseDown}
      onClick={handleClick}
      onFocus={handleFocus}
      className={cn(menuItemBase({ menuVariant, state, colorVariant: variant }), className)}
    >
      {isDetail ? (
        <DetailItemLayout
          isFocused={isFocused}
          isSelected={isSelected}
          value={value}
          valueClassName={menuItemValue({ valueVariant, focused: isActive, active: isActive })}
          icon={icon}
        >
          {children}
        </DetailItemLayout>
      ) : (
        <DefaultItemLayout
          isFocused={isFocused}
          isSelected={isSelected}
          isDanger={isDanger}
          hotkey={hotkey}
          icon={icon}
        >
          {children}
        </DefaultItemLayout>
      )}
    </div>
  );
}

import { cva } from "class-variance-authority";

/** Allowed item state values. */
export type ItemState = "normal" | "focused" | "selected" | "disabled" | "disabledFocused";

export function getItemState(options: {
  disabled: boolean;
  isFocused: boolean;
  isSelected: boolean;
}): ItemState {
  const { disabled, isFocused, isSelected } = options;
  if (disabled && isFocused) return "disabledFocused";
  if (disabled) return "disabled";
  if (isFocused) return "focused";
  if (isSelected) return "selected";
  return "normal";
}

export const menuItemBase = cva("cursor-pointer w-full transition-colors", {
  variants: {
    menuVariant: {
      default: "px-4 py-3 flex items-center font-mono duration-75",
      detail:
        "px-4 py-4 flex justify-between items-center text-sm border-b border-border last:border-b-0",
    },
    state: {
      normal: "hover:bg-secondary group",
      focused: "font-bold",
      selected: "font-bold group",
      disabled: "opacity-50 cursor-not-allowed",
      disabledFocused: "opacity-60 cursor-not-allowed bg-secondary text-foreground",
    },
    colorVariant: {
      default: "",
      danger: "",
    },
  },
  compoundVariants: [
    { state: "focused", menuVariant: "detail", class: "shadow-[inset_0_0_15px_rgba(0,0,0,0.1)]" },
    { state: "disabled", menuVariant: "default", class: "hover:bg-transparent" },
    {
      state: "disabledFocused",
      menuVariant: "detail",
      class: "shadow-[inset_0_0_15px_rgba(0,0,0,0.1)]",
    },
    {
      colorVariant: "danger",
      state: "focused",
      class: "bg-error text-error-foreground",
    },
    { colorVariant: "default", state: "focused", class: "bg-primary text-primary-foreground" },
    {
      colorVariant: "danger",
      state: "selected",
      class: "bg-error text-error-foreground",
    },
    { colorVariant: "default", state: "selected", class: "bg-primary text-primary-foreground" },
    { colorVariant: "danger", state: "normal", menuVariant: "default", class: "text-error" },
  ],
  defaultVariants: { menuVariant: "default", state: "normal", colorVariant: "default" },
});

export const menuItemIndicator = cva(
  "pr-4 shrink-0 inline-flex items-center justify-center self-center leading-none font-mono text-xs",
  {
    variants: {
      idle: {
        true: "transition-opacity opacity-60 group-hover:opacity-100",
        false: "",
      },
    },
    defaultVariants: { idle: false },
  },
);

export const menuItemLabel = cva("tracking-wide", {
  variants: {
    idle: {
      true: "group-hover:text-foreground",
      false: "",
    },
  },
  defaultVariants: { idle: false },
});

export const menuItemValue = cva("font-mono text-xs", {
  variants: {
    valueVariant: {
      default: "",
      success: "",
      "success-badge": "border px-2 py-0.5 rounded",
      muted: "",
    },
    focused: {
      true: "uppercase tracking-wide",
      false: "",
    },
    active: {
      true: "",
      false: "",
    },
  },
  compoundVariants: [
    { valueVariant: "default", active: false, class: "text-muted-foreground" },
    { valueVariant: "success", active: false, class: "text-success" },
    {
      valueVariant: "success-badge",
      active: false,
      class: "text-success border-success/30 bg-success/10",
    },
    { valueVariant: "muted", active: false, class: "text-muted-foreground/60" },
    { valueVariant: "default", active: true, class: "text-current" },
    { valueVariant: "success", active: true, class: "text-current" },
    { valueVariant: "muted", active: true, class: "text-current" },
    {
      valueVariant: "success-badge",
      active: true,
      class: "border-success bg-success text-success-foreground",
    },
  ],
  defaultVariants: { valueVariant: "default", focused: false, active: false },
});

import type { ReactNode } from "react";
import { cn } from "@/lib/utils";

const INDICATOR_ACTIVE = "▌";
const INDICATOR_IDLE = ">";

const iconSlotBase =
  "pr-4 shrink-0 inline-flex w-5 items-center justify-center self-center leading-none relative -top-[2px]";

function MenuItemIndicator({
  isFocused,
  isSelected,
  className,
}: {
  isFocused: boolean;
  isSelected: boolean;
  className?: string;
}) {
  return (
    <span aria-hidden="true" className={cn(iconSlotBase, className)}>
      {isFocused || isSelected ? INDICATOR_ACTIVE : INDICATOR_IDLE}
    </span>
  );
}

function MenuItemIconSlot({
  icon,
  isFocused,
  isSelected,
  iconIdleClassName,
  indicatorIdleClassName,
}: {
  icon?: ReactNode;
  isFocused: boolean;
  isSelected: boolean;
  iconIdleClassName?: string;
  indicatorIdleClassName?: string;
}) {
  if (icon !== undefined) {
    const isEmphasized = isFocused || isSelected;
    return (
      <span aria-hidden="true" className={cn(iconSlotBase, !isEmphasized && iconIdleClassName)}>
        {icon}
      </span>
    );
  }
  return (
    <MenuItemIndicator
      isFocused={isFocused}
      isSelected={isSelected}
      className={indicatorIdleClassName}
    />
  );
}

interface DefaultItemLayoutProps {
  isFocused: boolean;
  isSelected: boolean;
  isDanger: boolean;
  /** Decorative hotkey label rendered as [n]. */
  hotkey?: number | string;
  /** Icon content rendered by the component. */
  icon?: ReactNode;
  /** MenuItem and MenuDivider children. */
  children: ReactNode;
}

export function DefaultItemLayout({
  isFocused,
  isSelected,
  isDanger,
  hotkey,
  icon,
  children,
}: DefaultItemLayoutProps) {
  const idleColor = isDanger ? "text-error" : "text-foreground";
  const isEmphasized = isFocused || isSelected;

  return (
    <>
      <MenuItemIconSlot
        icon={icon}
        isFocused={isFocused}
        isSelected={isSelected}
        iconIdleClassName={isEmphasized ? undefined : idleColor}
        indicatorIdleClassName={
          isEmphasized
            ? undefined
            : cn("transition-opacity opacity-0 group-hover:opacity-100", idleColor)
        }
      />
      {hotkey !== undefined && (
        // Keep the unbound label out of the accessible name and typeahead text.
        <span
          aria-hidden="true"
          className={
            isEmphasized
              ? "mr-4 shrink-0"
              : cn("mr-4 shrink-0 group-hover:text-foreground", idleColor)
          }
        >
          [{hotkey}]
        </span>
      )}
      <span
        className={cn("tracking-wide", !isEmphasized && !isDanger && "group-hover:text-foreground")}
      >
        {children}
      </span>
    </>
  );
}

interface DetailItemLayoutProps {
  isFocused: boolean;
  isSelected: boolean;
  /** Controlled value. */
  value?: ReactNode;
  valueClassName: string;
  /** Icon content rendered by the component. */
  icon?: ReactNode;
  /** MenuItem and MenuDivider children. */
  children: ReactNode;
}

export function DetailItemLayout({
  isFocused,
  isSelected,
  value,
  valueClassName,
  icon,
  children,
}: DetailItemLayoutProps) {
  const isEmphasized = isFocused || isSelected;

  return (
    <>
      <div className="flex items-center">
        <MenuItemIconSlot
          icon={icon}
          isFocused={isFocused}
          isSelected={isSelected}
          indicatorIdleClassName={
            !isEmphasized
              ? "text-foreground opacity-0 group-hover:opacity-100 transition-opacity"
              : undefined
          }
        />
        <span className={isEmphasized ? undefined : "font-medium group-hover:text-foreground"}>
          {children}
        </span>
      </div>
      {value !== undefined && value !== null && <div className={valueClassName}>{value}</div>}
    </>
  );
}

"use client";

import { cn } from "@/lib/utils";

/** Props for menu divider. */
export interface MenuDividerProps {
  /** Class applied to the separator. Renders role="separator" with horizontal orientation. */
  className?: string;
}

/** Visual separator between groups. */
export function MenuDivider({ className }: MenuDividerProps) {
  return (
    <hr
      aria-orientation="horizontal"
      className={cn("my-1 border-t border-border mx-4 opacity-50", className)}
    />
  );
}

"use client";

import { createContext, useContext } from "react";

export type CustomActivator = () => void;

/** Context value shared by menu. */
export interface MenuContextValue {
  /**
   * Controlled selected item id. Pair with onSelect. Switches item role to "menuitemradio" with
   * aria-checked.
   */
  selectedId: string | null;
  /** Controlled highlighted (focused) item id. Pair with onHighlightChange. */
  highlighted: string | null;
  /** Activates an item in menu. */
  activate: (id: string) => void;
  /** Notifies the owning root menu when a nested menu item is activated. */
  notifySelect: (id: string) => void;
  /** Highlights an item in menu. */
  highlight: (id: string) => void;
  /**
   * Visual layout. `detail` renders taller, divider-separated rows with a right-aligned value
   * column, for menus where each item carries a status or summary value.
   */
  variant: "default" | "detail";
  idPrefix: string;
  itemRole: "menuitem" | "menuitemradio";
  /** Registers item with menu. */
  registerItem: (
    registrationId: string,
    value: string,
    disabled: boolean,
    element: HTMLElement | null,
  ) => void;
  /** Unregisters item from menu. */
  unregisterItem: (registrationId: string) => void;
  /** Registers activator with menu. */
  registerActivator: (id: string, handler: CustomActivator) => void;
  /** Unregisters activator from menu. */
  unregisterActivator: (id: string) => void;
}

/** React context backing menu. */
export const MenuContext = createContext<MenuContextValue | undefined>(undefined);

/** Reads the menu context. */
export function useMenuContext(): MenuContextValue {
  const context = useContext(MenuContext);
  if (context === undefined) {
    throw new Error("Menu parts must be used within a Menu");
  }
  return context;
}

"use client";

import { type ReactNode, useId } from "react";
import { cn } from "@/lib/utils";
import { MenuLabel } from "./menu-label";

/** Props for menu group. */
export interface MenuGroupProps {
  /**
   * Optional label rendered via MenuLabel. When provided, the group is labelled via
   * aria-labelledby.
   */
  label?: ReactNode;
  /** MenuItem, MenuItemCheckbox, MenuItemRadio, or MenuDivider children. */
  children: ReactNode;
  /** Additional class names merged onto the rendered element. */
  className?: string;
}

/** Semantic group with optional label. */
export function MenuGroup({ label, children, className }: MenuGroupProps) {
  const labelId = useId();
  const hasLabel = label !== undefined && label !== null;

  return (
    // biome-ignore lint/a11y/useSemanticElements: role="group" labels a related set of menu items; <fieldset> is for form controls and is not appropriate inside a menu.
    <div role="group" aria-labelledby={hasLabel ? labelId : undefined} className={cn(className)}>
      {hasLabel && <MenuLabel id={labelId}>{label}</MenuLabel>}
      {children}
    </div>
  );
}

"use client";

import {
  type ComponentPropsWithRef,
  type ReactNode,
  type Ref,
  useEffect,
  useId,
  useLayoutEffect,
  useRef,
} from "react";
import { useComposedRefs } from "@/hooks/use-composed-refs";
import { useControllableState } from "@/hooks/use-controllable-state";
import { getEncodedListboxItemId } from "@/hooks/use-listbox";
import { cn } from "@/lib/utils";
import { useMenuContext } from "./menu-context";
import { getItemState, menuItemBase, menuItemIndicator, menuItemLabel } from "./menu-item-variants";
import { useMenuItemInteractions } from "./use-menu-item-interactions";

const CHECKBOX_CHECKED = "[x]";
const CHECKBOX_UNCHECKED = "[ ]";

/** Props for menu item checkbox. */
export interface MenuItemCheckboxProps
  extends Omit<
    ComponentPropsWithRef<"div">,
    | "id"
    | "children"
    | "role"
    | "aria-checked"
    | "aria-disabled"
    | "data-value"
    | "onChange"
    | "ref"
  > {
  /** Stable identifier for the checkbox item. */
  id: string;
  /** Controlled checked state. */
  checked?: boolean;
  /** Initial checked state for uncontrolled mode. */
  defaultChecked?: boolean;
  /** Fired when the checked state toggles. */
  onChange?: (checked: boolean) => void;
  /** Disables the checkbox item. */
  disabled?: boolean;
  /** Checkbox item label. */
  children: ReactNode;
  /** Ref forwarded to the underlying element. */
  ref?: Ref<HTMLDivElement>;
}

/** Toggleable checkbox item. */
export function MenuItemCheckbox({
  id,
  checked: controlledChecked,
  defaultChecked = false,
  onChange,
  disabled = false,
  children,
  className,
  ref,
  onClick,
  onFocus,
  onMouseDown,
  ...rootProps
}: MenuItemCheckboxProps) {
  const {
    highlighted,
    activate,
    highlight,
    idPrefix,
    registerItem,
    unregisterItem,
    registerActivator,
    unregisterActivator,
  } = useMenuContext();
  const registrationId = useId();
  const rootRef = useRef<HTMLDivElement>(null);
  const composedRef = useComposedRefs(rootRef, ref);

  const [isChecked, setIsChecked] = useControllableState<boolean>({
    value: controlledChecked,
    defaultValue: defaultChecked,
    onChange,
  });

  const isFocused = highlighted === id;
  const itemId = getEncodedListboxItemId(idPrefix, id);

  useLayoutEffect(() => {
    registerItem(registrationId, id, disabled, rootRef.current);
    return () => unregisterItem(registrationId);
  }, [registerItem, unregisterItem, registrationId, id, disabled]);

  useEffect(() => {
    const toggle = () => {
      if (disabled) return;
      setIsChecked((prev) => !prev);
    };
    registerActivator(id, toggle);
    return () => unregisterActivator(id);
  }, [id, disabled, registerActivator, unregisterActivator, setIsChecked]);

  const { handleClick, handleFocus, handleMouseDown } = useMenuItemInteractions({
    id,
    disabled,
    activate,
    highlight,
    onClick,
    onFocus,
    onMouseDown,
  });

  const state = getItemState({ disabled, isFocused, isSelected: false });

  return (
    // biome-ignore lint/a11y/useKeyWithClickEvents: Enter/Space toggle is handled centrally by the menu container via useNavigation, not per item.
    <div
      {...rootProps}
      ref={composedRef}
      id={itemId}
      role="menuitemcheckbox"
      tabIndex={-1}
      data-slot="menu-item-checkbox"
      data-diffgazer-navigation-item="true"
      data-value={id}
      data-highlighted={isFocused ? "" : undefined}
      aria-checked={isChecked}
      aria-disabled={disabled || undefined}
      onMouseDown={handleMouseDown}
      onClick={handleClick}
      onFocus={handleFocus}
      className={cn(
        menuItemBase({ menuVariant: "default", state, colorVariant: "default" }),
        className,
      )}
    >
      <span
        aria-hidden="true"
        className={menuItemIndicator({ idle: (!isFocused && !disabled) || undefined })}
      >
        {isChecked ? CHECKBOX_CHECKED : CHECKBOX_UNCHECKED}
      </span>
      <span className={menuItemLabel({ idle: (!isFocused && !disabled) || undefined })}>
        {children}
      </span>
    </div>
  );
}

